	self.isActive = isActive and isActive ~= 0 or false
	self.closeValue = pb.closeValue
	self.closeGrade = pb.closeGrade

	self.heroMaxStar =pb.heroMaxStar

	self.storyRewards = {}
	self.storyRewardsKey = {}
	local storyRewards = pb.storyRewards or {}
	for i,v in ipairs(storyRewards) do
		table.insert(self.storyRewards,v)
		self.storyRewardsKey[v] = v
	end
end

